import React, { useState } from 'react';
import { Link } from 'react-router-dom';

// ==========================================
// INDIVIDUAL PRODUCT CARD COMPONENT
// ==========================================
const ProductCard = ({ product }) => {
  // State to handle the transparent heart toggle
  const [isFavorite, setIsFavorite] = useState(false);

  // Fallbacks just in case some data is missing from your API/Redux
  const title = product?.Title || product?.title || 'Premium Product';
  const subtitle = product?.Material || product?.subtitle || 'Premium Finish';
  const price = product?.['Final Price'] || product?.price || '0';
  const originalPrice = product?.['Original Price'] || product?.originalPrice || '0';
  const discount = product?.['Discount (%)'] || product?.discount || '0';
  const image = product?.['Image URL'] || product?.image || product?.imageURL || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=400';
  const inStock = product?.['Stock Status'] !== 'Out of Stock';

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-md transition-all duration-300 flex flex-col relative group">

      {/* --- TOP IMAGE AREA --- */}
      <div className="relative w-full h-56 bg-gray-50 overflow-hidden">
        <Link to={`/product/${product?.id || 'demo'}`}>
          <img
            src={image}
            alt={title}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
          />
        </Link>

        {/* Discount Badge (Top Left) */}
        {Number(discount) > 0 && (
          <div className="absolute top-3 left-3 bg-[#e23636] text-white px-2 py-1 rounded text-[11px] font-bold shadow-sm z-10 pointer-events-none">
            {discount}% OFF
          </div>
        )}

        {/* ========================================================
            🚀 FAVORITE BUTTON (Transparent, No Outlines, Scaling)
            ======================================================== */}
        <button
          onClick={(e) => {
            e.preventDefault(); // Prevents clicking the heart from navigating
            setIsFavorite(!isFavorite);
          }}
          className="absolute top-3 right-3 p-2 group/heart transition-all duration-200 bg-transparent border-0 !outline-none focus:!outline-none !ring-0 focus:!ring-0 !shadow-none hover:scale-110 active:scale-95 z-10"
          style={{ WebkitTapHighlightColor: 'transparent' }}
          aria-label="Toggle Favorite"
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            className={`w-6 h-6 transition-all duration-200 ${isFavorite
              ? 'fill-[#ef4444] text-[#ef4444]' // Active: Solid Red
              : 'fill-transparent text-gray-400 group-hover/heart:text-[#ef4444]' // Inactive: Transparent, Red outline on hover
              }`}
            viewBox="0 0 24 24"
            stroke="currentColor"
            strokeWidth="2"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"
            />
          </svg>
        </button>
      </div>

      {/* --- CONTENT AREA --- */}
      <div className="p-4 flex flex-col flex-grow">
        <Link to={`/product/${product?.id || 'demo'}`} className="block">
          <h3 className="text-[16px] font-bold text-gray-900 line-clamp-1 hover:text-[#f97316] transition-colors">
            {title}
          </h3>
          <p className="text-[13px] text-gray-500 mt-1 line-clamp-1">
            {subtitle}
          </p>
        </Link>

        {/* Pricing */}
        <div className="flex items-baseline gap-2 mt-2">
          <span className="text-[18px] font-bold text-gray-900">
            ₹{Number(price).toLocaleString('en-IN')}
          </span>
          {Number(originalPrice) > Number(price) && (
            <span className="text-[13px] text-gray-400 line-through">
              ₹{Number(originalPrice).toLocaleString('en-IN')}
            </span>
          )}
        </div>

        {/* Stock Status */}
        <div className="flex items-center gap-1.5 mt-3 mb-4">
          {inStock ? (
            <>
              <svg className="w-4 h-4 text-green-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
              <span className="text-[13px] text-green-600 font-medium">In Stock</span>
            </>
          ) : (
            <>
              <svg className="w-4 h-4 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
              <span className="text-[13px] text-red-500 font-medium">Out of Stock</span>
            </>
          )}
        </div>

        <div className="mt-auto">
          {/* ========================================================
              🚀 ADD TO CART BUTTON (Strict outline removal applied)
              ======================================================== */}
          <button
            disabled={!inStock}
            className={`w-full py-2.5 rounded-md font-bold text-[14px] flex items-center justify-center gap-2 transition-all duration-200 border-0 !outline-none focus:!outline-none focus-visible:!outline-none !ring-0 !ring-offset-0 focus:!ring-0 focus:!ring-offset-0 focus-visible:!ring-0 focus-visible:!ring-offset-0 select-none !shadow-none bg-clip-padding ${inStock
              ? 'bg-[#f97316] text-white hover:bg-[#ea580c] cursor-pointer'
              : 'bg-gray-200 text-gray-500 cursor-not-allowed'
              }`}
            style={{ WebkitTapHighlightColor: 'transparent' }}
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" />
            </svg>
            ADD TO CART
          </button>
        </div>
      </div>
    </div>
  );
};

// ==========================================
// MAIN GRID COMPONENT
// ==========================================
const ProductGrid = ({ title, subtitle, products = [] }) => {
  return (
    <section className="w-full py-8 bg-white">
      <div className="container mx-auto px-4 md:px-8">

        {/* Header Section */}
        {(title || subtitle) && (
          <div className="mb-8 text-center md:text-left">
            {title && <h2 className="text-2xl md:text-3xl font-bold text-gray-900">{title}</h2>}
            {subtitle && <p className="text-gray-500 mt-2 text-sm md:text-base">{subtitle}</p>}
          </div>
        )}

        {/* Responsive Grid Layout matching your screenshot */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {products.map((product, index) => (
            <ProductCard key={product?.id || index} product={product} />
          ))}
        </div>

      </div>
    </section>
  );
};

export default ProductGrid;
